{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式キックオフを承認し、本日をもって正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "移行方式是拠点をグループに分けて段階的に切り替えるB案を採用し、本番リリース目標を9月末から10月15日に延期する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "認証とマスタ配信の基盤構築はサクラ商事さんとの共同利用（第3案）を採用し、本件に関する回答書を来週の金曜までに作成して送付する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "移行リハーサルの手順書作成をQA担当の白鳥千夏からインフラ担当の沼田賢一到り、6月5日までに完了させる。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "新システムでのユーザー権限設計（ロール定義作り直し）は今回の範囲外とし、稼働後の運用改善として別途検討する。",
      "decided_by": "東雲 美咲"
    },
    {
      "id": "D6",
      "content": "障害発生時の一次受け窓口をQAチーム（白鳥千夏）に設定し、情シスへの連絡回数を減らす。",
      "decided_by": "東雲 美咲"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "API仕様書のドラフト（エンドポイント一覧と主要項目レイアウト、証明書要件を含む別紙）を作成する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "検証環境用サーバーの調達依頼を出す（ラック空き確保を含む）。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "現場ヒアリングの対象部署リスト（表形式で部署名、窓口候補者など）を提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "ベンダー見積の社内稟議を起票する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "サクラ商事さんへの共同利用に関する回答書を作成・送付する。",
      "assignee": "桐生 遥",
      "due": "2026-05-19"
    },
    {
      "id": "A6",
      "task": "外部ライセンス費用の再見積も（年契約条件含む）と、ハード構成の見直しをまとめて提出する。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A7",
      "task": "負荷テスト計画（二段構えのシナリオ、合格基準・測定点定義など）を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A8",
      "task": "移行テスト計画（データ照合項目、切り戻し手順など）を作成する。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A9",
      "task": "移行リハーサルの手順書（作業実体、障害対応フローなど）を作成する。",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A10",
      "task": "移行リハーサルの手順書をレビューし、QA観点を確認する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-05"
    },
    {
      "id": "A11",
      "task": "各拠点の繁忙状況を考慮した説明会日程案（全体で4回に分けるなど）をまとめる。",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A12",
      "task": "既存テストケースの棚卸し（有効・無効・修正要、など）を行って一覧表を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-30"
    },
    {
      "id": "A13",
      "task": "移行方式決定に基づき、システム構成概要（ベンダー費用など）を精査した上で稟議に添付資料を整備する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A14",
      "task": "移行方式検討結果をベンダー（コマツバ・ソリューションズ）へ共有する。",
      "assignee": "郡司 明久",
      "due": "2026-05-31"
    },
    {
      "id": "A15",
      "task": "拠点ごとに段階的に移行を行うためのグループ分け案を整理し、最終スケジュール（10月15日完了）に合わせる。",
      "assignee": "芦田 巧",
      "due": "2026-06-30"
    },
    {
      "id": "A16",
      "task": "外部ライセンス単価（年契約条件含む）を再見積し、予算収支が許容範囲か確認する。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    }
  ],
